mapper.select:
SELECT
    id,
    name,
    type,
    monthly_amount AS monthlyAmount
FROM financial_node_snapshot
WHERE user_id = #{userId, jdbcType=VARCHAR}
          AND year = #{year}
          AND month = #{month}

SELECT
    from_snapshot_id AS source,
    to_snapshot_id AS target,
    amount AS value
FROM flow_snapshot
WHERE user_id = #{userId, jdbcType=VARCHAR}
  AND year = #{year}
  AND month = #{month}
